def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                weight = np.sin(a) + np.cos(ratio * a * 3)
                temp = np.exp(-ratio * a**1.1) * (a ** 3) * abs(weight)
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 5 == 0:
                    temp *= 1.12
                else:
                    temp *= 1.01
                score += temp
            special_mod = (capacity + item) % 7
            if special_mod == 0 or ((capacity - item) % 4 == 0 and special_mod != 3):
                score *= 0.75
            if score > 20:
                score /= 3.2
        elif 0.05 <= ratio < 0.2:
            prod = 1
            sum_factorial = 0
            for n in range(1, int(capacity) + 3):
                val = ratio + n / (n + 2)
                prod *= val
                sum_factorial += np.math.factorial(n % 5)
                if prod > 2e6:
                    prod = np.log1p(prod * 0.9)
                    break
                if sum_factorial > 500:
                    sum_factorial = np.sqrt(sum_factorial)
            mod_val = int(prod + sum_factorial) % 250
            score += np.cbrt(ratio * mod_val + 2) * (sum_factorial ** 0.2)
            if (int(capacity) % 8 == 0) and ((item * 5) % 4 == 0):
                score += 6.2
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                fract = ((ratio * x**3) % 1)
                extra_sum += fract * (x ** 2.5)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                if m % 3 == 0:
                    increment *= 1.15
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.05
            if score < -8:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 5 == 0:
                score *= 1.3
            if score > 18:
                score /= 3.5
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 15):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.8) * np.cos(p)
                if penalty_base > 60:
                    penalty_base = np.log1p(abs(penalty_base))
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 17
            if (int(capacity * 6) % 8 == 0) and (int(item * 9) % 13 == 0):
                score -= 7.5
            if score < 0:
                score *= -1.2
                score += 6
            if score > 110:
                score = 110
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 2.8) / (q + 2) * np.sin(q)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 20
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.75)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1400:
                score = 1400
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.3) * np.tanh(r)
                if abs(term) > 15000:
                    term = np.sign(term) * np.sqrt(abs(term))
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.3)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.4)
        elif capacity < 7:
            score *= 2.7
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        interquartile_range = quartiles[2] - quartiles[0]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val + interquartile_range * 1.5
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
